            )
        }
        composable("settings") {
            SettingsRoute(
                onBackClick = { navController.popBackStack() },
                onEditProfileClick = { navController.navigate("update_profile") },
                onChangePasswordClick = { navController.navigate("change_password") }
            )
        }
        composable("change_password") {
            ChangePasswordRoute(
                onBackClick = { navController.popBackStack() },
