                    navController.previousBackStackEntry?.savedStateHandle?.set("pickup_lat", pickLat)
                    navController.previousBackStackEntry?.savedStateHandle?.set("pickup_lng", pickLng)
                    navController.popBackStack()
                }
            )
        }
    }
}

@Composable
private fun MainScreen(
    role: String,
    onLogout: () -> Unit,
    onNavigate: (String) -> Unit,
    navController: NavHostController
) {
    val tabs = remember(role) { tabsForRole(role) }
    var selectedIndex by rememberSaveable { mutableIntStateOf(0) }
    val savedStateHandle = navController.currentBackStackEntry?.savedStateHandle
    val pickupLabel = savedStateHandle?.get<String>("pickup_label")
    val pickupLat = savedStateHandle?.get<Double>("pickup_lat")
    val pickupLng = savedStateHandle?.get<Double>("pickup_lng")
    val pickupSelection = if (pickupLabel != null && pickupLat != null && pickupLng != null) {
        PickupSelection(pickupLabel, pickupLat, pickupLng)
    } else {
        null
    }
    var lastPickupLat by rememberSaveable { mutableStateOf(10.2897) }
    var lastPickupLng by rememberSaveable { mutableStateOf(123.8628) }

    LaunchedEffect(pickupSelection) {
        pickupSelection?.let {
            lastPickupLat = it.lat
            lastPickupLng = it.lng
        }
    }

    Scaffold(
        bottomBar = {
            NavigationBar(containerColor = Color.Black) {
                tabs.forEachIndexed { index, tab ->
                    NavigationBarItem(
                        selected = selectedIndex == index,
                        onClick = { selectedIndex = index },
                        icon = {
                            Icon(tab.icon, contentDescription = tab.label,
                                tint = if (selectedIndex == index) Color.White else Color(0xFF666666))
                        },
                        label = {
                            Text(tab.label, fontFamily = FontFamily.Monospace, fontSize = 10.sp,
                                color = if (selectedIndex == index) Color.White else Color(0xFF666666))
                        },
                        colors = NavigationBarItemDefaults.colors(
                            indicatorColor = Color(0xFF222222)
                        )
                    )
                }
            }
        }
    ) { padding ->
        Box(modifier = Modifier.padding(padding)) {
            when (tabs.getOrNull(selectedIndex)?.key) {
                // Rider
                "home" -> DashboardRoute(
                    onProfileClick = { onNavigate("profile_detail") },
                    onLogoutClick = onLogout,
                    onPickupLocationClick = {
                        navController.navigate("location_picker?lat=$lastPickupLat&lng=$lastPickupLng")
                    },
                    pickupSelection = pickupSelection,
                    onPickupSelectionConsumed = {
                        savedStateHandle?.remove<String>("pickup_label")
                        savedStateHandle?.remove<Double>("pickup_lat")
                        savedStateHandle?.remove<Double>("pickup_lng")
                    }
                )
                // Driver
                "driver_requests" -> DriverRoute()
                // Admin
                "admin" -> AdminRoute(
                    onUsersClick = { onNavigate("admin_users_detail") },
                    onVerificationsClick = { onNavigate("admin_verif_detail") }
                )
                "admin_users" -> AdminUsersRoute(onBackClick = {})
                "admin_verif" -> AdminVerificationsRoute(onBackClick = {})
                // Shared
                "messages" -> MessagesRoute(
                    onConversationClick = { id -> onNavigate("conversation/$id") }
                )
                "profile" -> ProfileRoute(
                    onBackClick = {},
                    onUpdateProfileClick = { onNavigate("update_profile") },
                    onSettingsClick = { onNavigate("settings") },
                    onRideHistoryClick = { onNavigate("ride_history") }
                )
            }
        }
    }
}

package com.example.uni_lift.features.messages

import com.example.uni_lift.core.supabase.SupabaseProvider
import io.github.jan.supabase.auth.auth
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.SupervisorJob
import kotlinx.coroutines.cancel
import kotlinx.coroutines.launch
import java.time.LocalTime
import java.time.format.DateTimeFormatter

class ConversationPresenter(
    private val repository: ConversationContract.Repository,
    private val token: String,
    private val conversationId: String
) : ConversationContract.Presenter {

    private var view: ConversationContract.View? = null
    private var state = ConversationContract.UiState()
    private val scope = CoroutineScope(Dispatchers.Main + SupervisorJob())
    private val timeFormatter = DateTimeFormatter.ofPattern("HH:mm")

    override fun attach(view: ConversationContract.View) {
        this.view = view
        loadConversation()
    }

    override fun detach() {
        scope.launch {
            repository.unsubscribeFromMessages()
        }
        view = null
        scope.cancel()
    }

    override fun onInputChanged(text: String) {
        state = state.copy(inputText = text)
        view?.render(state)
    }

    override fun onSendClicked() {
        val text = state.inputText.trim()
        if (text.isBlank()) return

        // Clear input immediately for responsiveness
        state = state.copy(inputText = "")
        view?.render(state)

        // Persist to Supabase — the realtime subscription will add it to the UI
        scope.launch {
            repository.sendMessage(conversationId, text).fold(
                onSuccess = { /* message will arrive via realtime */ },
                onFailure = { err ->
                    state = state.copy(error = err.message)
                    view?.render(state)
                }
            )
        }
    }

    override fun onAcceptOffer(msgId: String) {
        val updated = state.messages.map { msg ->
            if (msg.id == msgId) msg.copy(offerStatus = "ACCEPTED") else msg
        }
        val systemMsg = ChatMessage(
            id = "msg_sys_${System.currentTimeMillis()}",
            sender = "system",
            text = "OFFER ACCEPTED",
            time = LocalTime.now().format(timeFormatter)
        )
        state = state.copy(messages = updated + systemMsg)
        view?.render(state)
    }

    override fun onDeclineOffer(msgId: String) {
        val updated = state.messages.map { msg ->
            if (msg.id == msgId) msg.copy(offerStatus = "DECLINED") else msg
        }
        val systemMsg = ChatMessage(
            id = "msg_sys_${System.currentTimeMillis()}",
            sender = "system",
            text = "OFFER DECLINED",
            time = LocalTime.now().format(timeFormatter)
        )
        state = state.copy(messages = updated + systemMsg)
        view?.render(state)
    }

    override fun onSosClicked() {
        val sosMsg = ChatMessage(
            id = "msg_sos_${System.currentTimeMillis()}",
            sender = "system",
            text = "SOS ALERT SENT",
            time = LocalTime.now().format(timeFormatter)
        )
        state = state.copy(messages = state.messages + sosMsg)
        view?.render(state)
    }

    private fun loadConversation() {
        state = state.copy(isLoading = true)
        view?.render(state)

        scope.launch {
            val result = repository.getConversation(token, conversationId)
            result.fold(
                onSuccess = { (conversation, messages) ->
                    state = state.copy(
                        conversation = conversation,
                        messages = messages,
                        isLoading = false
                    )
                    view?.render(state)

                    // Subscribe to realtime messages
                    subscribeToRealtime()
                },
                onFailure = {
                    state = state.copy(isLoading = false, error = it.message)
                    view?.render(state)
                }
            )
        }
    }

    private fun subscribeToRealtime() {
        val currentUserId = SupabaseProvider.client.auth.currentSessionOrNull()?.user?.id ?: return
        scope.launch {
            repository.subscribeToMessages(conversationId, currentUserId) { newMessage ->
                // Avoid duplicates: check if the message ID already exists
                if (state.messages.none { it.id == newMessage.id }) {
                    state = state.copy(messages = state.messages + newMessage)
                    view?.render(state)
                }
            }
        }
    }
}

package com.example.uni_lift.features.messages

import com.example.uni_lift.core.supabase.SupabaseProvider
import io.github.jan.supabase.auth.auth
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.SupervisorJob
import kotlinx.coroutines.cancel
import kotlinx.coroutines.launch
import kotlinx.coroutines.Job
import kotlinx.coroutines.delay
import java.time.LocalTime
import java.time.format.DateTimeFormatter

class ConversationPresenter(
    private val repository: ConversationContract.Repository,
    private val token: String,
    private val conversationId: String
) : ConversationContract.Presenter {

    private var view: ConversationContract.View? = null
    private var state = ConversationContract.UiState()
    private val scope = CoroutineScope(Dispatchers.Main + SupervisorJob())
    private val timeFormatter = DateTimeFormatter.ofPattern("HH:mm")
    private var refreshJob: Job? = null

    override fun attach(view: ConversationContract.View) {
        this.view = view
        loadConversation()
    }

    override fun detach() {
        scope.launch {
            repository.unsubscribeFromMessages()
        }
        refreshJob?.cancel()
        refreshJob = null
        view = null
        scope.cancel()
    }

    override fun onInputChanged(text: String) {
        state = state.copy(inputText = text)
        view?.render(state)
    }

    override fun onSendClicked() {
        val text = state.inputText.trim()
        if (text.isBlank()) return

        // Clear input immediately for responsiveness
        state = state.copy(inputText = "")
        view?.render(state)

        // Optimistically add the message so the UI updates immediately.
        val localId = "local_${System.currentTimeMillis()}"
        val localMessage = ChatMessage(
            id = localId,
            sender = "self",
            text = text,
            time = LocalTime.now().format(timeFormatter)
        )
        state = state.copy(messages = state.messages + localMessage)
        view?.render(state)

        // Persist to Supabase — the realtime subscription will add it to the UI
        scope.launch {
            repository.sendMessage(conversationId, text).fold(
                onSuccess = { /* message will arrive via realtime */ },
                onFailure = { err ->
                    state = state.copy(error = err.message)
                    view?.render(state)
                }
            )
        }
    }

    override fun onAcceptOffer(msgId: String) {
        val updated = state.messages.map { msg ->
            if (msg.id == msgId) msg.copy(offerStatus = "ACCEPTED") else msg
        }
        val systemMsg = ChatMessage(
            id = "msg_sys_${System.currentTimeMillis()}",
            sender = "system",
            text = "OFFER ACCEPTED",
            time = LocalTime.now().format(timeFormatter)
        )
        state = state.copy(messages = updated + systemMsg)
        view?.render(state)
    }

    override fun onDeclineOffer(msgId: String) {
        val updated = state.messages.map { msg ->
            if (msg.id == msgId) msg.copy(offerStatus = "DECLINED") else msg
        }
        val systemMsg = ChatMessage(
            id = "msg_sys_${System.currentTimeMillis()}",
            sender = "system",
            text = "OFFER DECLINED",
            time = LocalTime.now().format(timeFormatter)
        )
        state = state.copy(messages = updated + systemMsg)
        view?.render(state)
    }

    override fun onSosClicked() {
        val sosMsg = ChatMessage(
            id = "msg_sos_${System.currentTimeMillis()}",
            sender = "system",
            text = "SOS ALERT SENT",
            time = LocalTime.now().format(timeFormatter)
        )
        state = state.copy(messages = state.messages + sosMsg)
        view?.render(state)
    }

    private fun loadConversation() {
        state = state.copy(isLoading = true)
        view?.render(state)

        scope.launch {
            val result = repository.getConversation(token, conversationId)
            result.fold(
                onSuccess = { (conversation, messages) ->
                    state = state.copy(
                        conversation = conversation,
                        messages = messages,
                        isLoading = false
                    )
                    view?.render(state)

                    // Subscribe to realtime messages
                    subscribeToRealtime()
                    startMessageRefresh()
                },
                onFailure = {
                    state = state.copy(isLoading = false, error = it.message)
                    view?.render(state)
                }
            )
        }
    }

    private fun subscribeToRealtime() {
        val currentUserId = SupabaseProvider.client.auth.currentSessionOrNull()?.user?.id ?: return
        scope.launch {
            repository.subscribeToMessages(conversationId, currentUserId) { newMessage ->
                // Replace optimistic local self message if the realtime one arrives.
                val normalized = if (newMessage.sender == "self") {
                    val dropIndex = state.messages.indexOfFirst {
                        it.id.startsWith("local_") && it.sender == "self" && it.text == newMessage.text
                    }
                    if (dropIndex >= 0) state.messages.toMutableList().also { it.removeAt(dropIndex) } else state.messages
                } else {
                    state.messages
                }

                // Avoid duplicates: check if the message ID already exists
                if (normalized.none { it.id == newMessage.id }) {
                    state = state.copy(messages = normalized + newMessage)
                    view?.render(state)
                }
            }
        }
    }

    private fun startMessageRefresh() {
        if (refreshJob != null) return
        refreshJob = scope.launch {
            while (true) {
                delay(4000)
                repository.getConversation(token, conversationId).onSuccess { (_, messages) ->
                    if (messages.size > state.messages.size) {
                        state = state.copy(messages = messages)
                        view?.render(state)
                    }
                }
            }
        }
    }
}

package com.example.uni_lift.features.messages

import com.example.uni_lift.core.supabase.ConversationRow
import com.example.uni_lift.core.supabase.LastMessageAtUpdate
import com.example.uni_lift.core.supabase.MessageInsert
import com.example.uni_lift.core.supabase.MessageRow
import com.example.uni_lift.core.supabase.SupabaseProvider
import com.example.uni_lift.core.supabase.UserRow
import io.github.jan.supabase.auth.auth
import io.github.jan.supabase.postgrest.from
import io.github.jan.supabase.postgrest.query.Order
import io.github.jan.supabase.realtime.channel
import io.github.jan.supabase.realtime.postgresChangeFlow
import io.github.jan.supabase.realtime.PostgresAction
import io.github.jan.supabase.realtime.RealtimeChannel
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.SupervisorJob
import kotlinx.coroutines.cancel
import kotlinx.coroutines.flow.launchIn
import kotlinx.coroutines.flow.onEach
import kotlinx.coroutines.withContext
import kotlinx.serialization.json.jsonPrimitive
import java.time.Instant
import java.time.ZoneId
import java.time.format.DateTimeFormatter

class ConversationRepository : ConversationContract.Repository {

    private var realtimeChannel: RealtimeChannel? = null
    private var realtimeScope: CoroutineScope? = null

    override suspend fun getConversation(
        token: String,
        conversationId: String
    ): Result<Pair<Conversation, List<ChatMessage>>> =
        withContext(Dispatchers.IO) {
            runCatching {
                val client = SupabaseProvider.client
                val currentUserId = client.auth.currentSessionOrNull()?.user?.id ?: ""

                val convRow = client.from("conversations")
                    .select { filter { eq("id", conversationId) } }
                    .decodeSingle<ConversationRow>()

                // Resolve partner name
                val partnerId = if (convRow.riderId == currentUserId) convRow.driverId else convRow.riderId
                val partnerName = try {
                    client.from("users")
                        .select { filter { eq("id", partnerId) } }
                        .decodeList<UserRow>()
                        .firstOrNull()?.fullName ?: "User"
                } catch (_: Exception) { "User" }

                val initials = partnerName
                    .split(" ")
                    .mapNotNull { it.firstOrNull()?.uppercaseChar() }
                    .take(2)
                    .joinToString("")
                    .ifEmpty { "?" }

                val conversation = Conversation(
                    id = convRow.id,
                    partnerId = partnerId,
                    partnerName = partnerName,
                    partnerInitials = initials,
                    rideId = convRow.rideId ?: "",
                    pickup = convRow.pickup ?: "",
                    dropoff = convRow.dropoff ?: "",
                    lastMessage = "",
                    timeAgo = convRow.lastMessageAt ?: "",
                    status = convRow.status
                )

                val messageRows = client.from("messages")
                    .select {
                        filter { eq("conversation_id", conversationId) }
                        order("sent_at", Order.ASCENDING)
                    }
                    .decodeList<MessageRow>()

                val messages = messageRows.map { row ->
                    val sender = when {
                        row.type == "system" -> "system"
                        row.senderId == currentUserId -> "self"
                        else -> "other"
                    }
                    ChatMessage(
                        id = row.id,
                        sender = sender,
                        text = row.content,
                        time = formatMessageTime(row.sentAt),
                        offerAmount = row.offerAmount,
                        offerStatus = row.offerStatus
                    )
                }

                conversation to messages
            }
        }

    override suspend fun sendMessage(
        conversationId: String,
        content: String,
        type: String,
        offerAmount: Double?
    ): Result<Unit> =
        withContext(Dispatchers.IO) {
            runCatching {
                val client = SupabaseProvider.client
                val senderId = client.auth.currentSessionOrNull()?.user?.id
                    ?: error("Not authenticated")
                client.from("messages").insert(
                    MessageInsert(
                        conversationId = conversationId,
                        rideId = null,
                        senderId = senderId,
                        content = content,
                        type = type,
                        offerAmount = offerAmount,
                        offerStatus = if (type == "offer") "PENDING" else null
                    )
                )
                // Update last_message_at on the conversation
                client.from("conversations")
                    .update(LastMessageAtUpdate(lastMessageAt = Instant.now().toString())) {
                        filter { eq("id", conversationId) }
                    }
                Unit
            }
        }

    override suspend fun subscribeToMessages(
        conversationId: String,
        currentUserId: String,
        onNewMessage: (ChatMessage) -> Unit
    ) {
        try {
            val client = SupabaseProvider.client
            realtimeScope = CoroutineScope(Dispatchers.Main + SupervisorJob())

            val channel = client.channel("messages-$conversationId")
            realtimeChannel = channel

            val flow = channel.postgresChangeFlow<PostgresAction.Insert>(schema = "public") {
                table = "messages"
            }

            flow.onEach { action ->
                val record = action.record
                // Client-side filter: only process messages for this conversation
                val msgConvId = record["conversation_id"]?.jsonPrimitive?.content ?: ""
                if (msgConvId != conversationId) return@onEach

                val senderId = record["sender_id"]?.jsonPrimitive?.content ?: ""
                val msgType = record["type"]?.jsonPrimitive?.content ?: "text"
                val sender = when {
                    msgType == "system" -> "system"
                    senderId == currentUserId -> "self"
                    else -> "other"
                }
                val chatMessage = ChatMessage(
                    id = record["id"]?.jsonPrimitive?.content ?: "rt_${System.currentTimeMillis()}",
                    sender = sender,
                    text = record["content"]?.jsonPrimitive?.content ?: "",
                    time = formatMessageTime(record["sent_at"]?.jsonPrimitive?.content),
                    offerAmount = record["offer_amount"]?.jsonPrimitive?.content?.toDoubleOrNull(),
                    offerStatus = record["offer_status"]?.jsonPrimitive?.content
                )
                onNewMessage(chatMessage)
            }.launchIn(realtimeScope!!)

            channel.subscribe()
        } catch (e: Exception) {
            e.printStackTrace()
        }
    }

    override suspend fun unsubscribeFromMessages() {
        try {
            realtimeChannel?.unsubscribe()
            realtimeScope?.cancel()
            realtimeChannel = null
            realtimeScope = null
        } catch (_: Exception) {}
    }

    private fun formatMessageTime(isoTimestamp: String?): String {
        if (isoTimestamp.isNullOrBlank()) return ""
        return try {
            val instant = Instant.parse(isoTimestamp)
            val formatter = DateTimeFormatter.ofPattern("HH:mm")
            instant.atZone(ZoneId.systemDefault()).format(formatter)
        } catch (_: Exception) {
            isoTimestamp.take(5)
        }
    }
}

