interface View { fun render(state: UiState) fun navigateToProfile() fun navigateToLogin() }
interface Presenter { fun attach(view: View) fun detach() fun onProfileClicked() fun onLogoutClicked() fun onPickupChanged(value: String) fun onDropoffChanged(value: String) fun onPassengerCountChanged(count: Int) fun onFareChanged(value: String) fun onVehicleTypeChanged(type: String) fun onFindDriverClicked() fun onCancelRideClicked() fun onToggleMap() }
interface Repository { suspend fun getActiveRide(token: String): Result<RideRecord?> suspend fun createRide(token: String, form: BookingForm): Result<RideRecord> suspend fun cancelRide(token: String, rideId: String): Result<Unit> } }

